commits.content:
.navbar-brand {
  font-family: 'Poppins', sans-serif;
  font-size: 1.5rem;
  letter-spacing: 0.5px;
}

.nav-link {
  font-weight: 500;
  transition: color 0.3s;
}

.nav-link:hover,
.nav-link.active {
  color: #000000ff;
}
